class Solution:
    def discountPrices(self, sentence: str, discount: int) -> str:
        words = sentence.split()
        for i, w in enumerate(words):
            if w.startswith('$') and len(w) > 1 and w[1:].isdigit():
                price = int(w[1:])
                new_price = price * (100 - discount) / 100
                words[i] = f"${new_price:.2f}"
        return ' '.join(words)
```
